machine StorageProxy {
  var db: machine;

  // Per-key latest committed value known to the proxy.
  var lastCommit: map[int, int];

  // Monotonic operation id for internal tracking.
  var nextOpId: int;

  // Storage-facing request queue.
  type tProxyReq = (opId: int, caller: machine, isWrite: bool, key: int, value: int, podId: int);
  var queue: seq[tProxyReq];

  // Per-key in-flight operation (to correlate storage responses).
  var inFlightByKey: map[int, int]; // key -> opId
  var pendingByOp: map[int, tProxyReq]; // opId -> request

  // Internal tick to model forwarding/holding behavior.
  event eProxyTick;

  start state Init {
    entry (p: (db: machine)) {
      db = p.db;
      lastCommit = default(map[int, int]);
      nextOpId = 1;
      queue = default(seq[tProxyReq]);
      inFlightByKey = default(map[int, int]);
      pendingByOp = default(map[int, tProxyReq]);
    }

    on eStorageRead do (req: (caller: machine, key: int, podId: int)) {
      HandleIncomingRead(req.caller, req.key, req.podId);
    }

    on eStorageWrite do (req: (caller: machine, key: int, value: int, podId: int)) {
      HandleIncomingWrite(req.caller, req.key, req.value, req.podId);
    }

    on eStorageReadResp do (resp: (key: int, value: int)) {
      HandleStorageReadResp(resp.key, resp.value);
    }

    on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
      HandleStorageWriteResp(resp.key, resp.success, resp.value);
    }

    on eProxyTick do {
      MaybeForwardOrHold();
    }
  }

  fun HandleIncomingRead(caller: machine, key: int, podId: int) {
    var served: bool;
    // Announce request arrival from pod/cache to proxy.
    send this, eMonitorProxyRequestIssued, (key = key, podId = podId, isWrite = false);

    served = TryServeDirectRead(caller, key, podId);
    if (!served) {
      EnqueueRequest(caller, false, key, 0, podId);
    }
  }

  fun HandleIncomingWrite(caller: machine, key: int, value: int, podId: int) {
    // Announce request arrival from pod/cache to proxy.
    send this, eMonitorProxyRequestIssued, (key = key, podId = podId, isWrite = true);
    // Writes must go to storage to commit.
    EnqueueRequest(caller, true, key, value, podId);
  }

  fun TryServeDirectRead(caller: machine, key: int, podId: int) : bool {
    var canServe: bool;
    var resp: (key: int, value: int, fromCache: bool);
    canServe = false;

    if ((key in lastCommit) && !(key in inFlightByKey)) {
      // Safe to serve from proxy's authoritative mirror.
      resp = (key = key, value = lastCommit[key], fromCache = true);
      send caller, eReadResp, resp;
      // Announce logical response delivered by proxy.
      send this, eMonitorProxyResponseDelivered, (key = key, podId = podId, isWrite = false);
      canServe = true;
    }

    return canServe;
  }

  fun EnqueueRequest(caller: machine, isWrite: bool, key: int, value: int, podId: int) {
    var opId: int;
    var req: tProxyReq;
    var pending: int;

    opId = nextOpId;
    nextOpId = nextOpId + 1;
    req = (opId = opId, caller = caller, isWrite = isWrite, key = key, value = value, podId = podId);

    queue += (sizeof(queue), req);
    pending = sizeof(queue);
    // Announce enqueue
    send this, eMonitorProxyEnqueue, (key = key, podId = podId, isWrite = isWrite, pending = pending);
    // Kick the proxy scheduler
    send this, eProxyTick;
  }

  fun MaybeForwardOrHold() {
    var didForward: bool;
    var pending: int;

    pending = sizeof(queue);
    if (pending == 0) {
      return;
    }

    // Nondeterministically decide to hold or try to forward.
    if ($) {
      // Hold step: do not forward any request this tick.
      send this, eMonitorProxyHold, (pending = pending);
      // Reschedule to allow progress later.
      send this, eProxyTick;
      return;
    }

    didForward = TryForwardOne();
    if (!didForward) {
      // Could not forward due to per-key in-flight constraints; model a hold.
      send this, eMonitorProxyHold, (pending = pending);
      send this, eProxyTick;
    }
  }

  fun TryForwardOne() : bool {
    var pos: int;
    var found: bool;
    var req: tProxyReq;
    var pending: int;

    pending = sizeof(queue);
    if (pending == 0) {
      return false;
    }

    // Find first eligible request whose key has no in-flight op.
    pos = 0;
    found = false;
    while (pos < sizeof(queue)) {
      req = queue[pos];
      if (!(req.key in inFlightByKey)) {
        found = true;
        break;
      }
      pos = pos + 1;
    }

    if (!found) {
      return false;
    }

    // Mark in-flight and remember for response matching.
    inFlightByKey[req.key] = req.opId;
    pendingByOp[req.opId] = req;

    // Announce forward before sending to storage.
    send this, eMonitorProxyForward, (key = req.key, podId = req.podId, isWrite = req.isWrite, pending = pending);

    if (req.isWrite) {
      send db, eStorageWrite, (caller = this, key = req.key, value = req.value, podId = req.podId);
    } else {
      send db, eStorageRead, (caller = this, key = req.key, podId = req.podId);
    }

    // Remove from queue.
    queue -= (pos);

    // Schedule next tick to continue draining or holding.
    send this, eProxyTick;

    return true;
  }

  fun HandleStorageReadResp(key: int, value: int) {
    var opId: int;
    var req: tProxyReq;
    var resp: (key: int, value: int, fromCache: bool);

    // Update authoritative mirror with committed value from storage.
    lastCommit[key] = value;

    if (key in inFlightByKey) {
      opId = inFlightByKey[key];
      req = pendingByOp[opId];

      // Deliver logical response to the requester.
      resp = (key = key, value = value, fromCache = false);
      send req.caller, eReadResp, resp;
      send this, eMonitorProxyResponseDelivered, (key = key, podId = req.podId, isWrite = false);

      // Clear in-flight tracking for this key/op.
      inFlightByKey -= (key);
      pendingByOp -= (opId);
    }
  }

  fun HandleStorageWriteResp(key: int, success: bool, value: int) {
    var opId: int;
    var req: tProxyReq;

    if (key in inFlightByKey) {
      opId = inFlightByKey[key];
      req = pendingByOp[opId];

      if (success) {
        // Update authoritative mirror on successful commit.
        lastCommit[key] = value;
      }

      // Deliver logical response to the requester.
      send req.caller, eWriteResp, (key = key, success = success);
      send this, eMonitorProxyResponseDelivered, (key = key, podId = req.podId, isWrite = true);

      // Clear in-flight tracking for this key/op.
      inFlightByKey -= (key);
      pendingByOp -= (opId);
    }
  }
}

machine CacheNode {
  var proxy: machine;
  var podId: int;

  // Coalesce multiple reads per key; one outstanding proxy read per key.
  var readIssued: set[int];
  var readWaiters: map[int, seq[machine]];

  // Serialize writes per key; one outstanding proxy write per key.
  type tWriteEntry = (client: machine, value: int);
  var writeQueues: map[int, seq[tWriteEntry]];
  var writeInFlight: set[int];

  start state Init {
    entry (p: (proxy: machine, podId: int)) {
      proxy = p.proxy;
      podId = p.podId;
      readIssued = default(set[int]);
      readWaiters = default(map[int, seq[machine]]);
      writeQueues = default(map[int, seq[tWriteEntry]]);
      writeInFlight = default(set[int]);
    }

    // Client API: read request
    on eClientRead do (req: (client: machine, key: int)) {
      HandleClientRead(req.client, req.key);
    }

    // Client API: write request
    on eClientWrite do (req: (client: machine, key: int, value: int)) {
      HandleClientWrite(req.client, req.key, req.value);
    }

    // Proxy logical responses back to this CacheNode
    on eReadResp do (resp: (key: int, value: int, fromCache: bool)) {
      DeliverReadToClients(resp.key, resp.value, resp.fromCache);
    }

    on eWriteResp do (resp: (key: int, success: bool)) {
      DeliverWriteToClient(resp.key, resp.success);
    }
  }

  fun HandleClientRead(client: machine, key: int) {
    var q: seq[machine];

    // Append client to waiters for this key.
    if (key in readWaiters) {
      q = readWaiters[key];
    } else {
      q = default(seq[machine]);
    }
    q += (sizeof(q), client);
    readWaiters[key] = q;

    // If not already issued to proxy, issue one read to proxy.
    if (!(key in readIssued)) {
      readIssued += (key);
      send proxy, eStorageRead, (caller = this, key = key, podId = podId);
    }
  }

  fun HandleClientWrite(client: machine, key: int, value: int) {
    var q: seq[tWriteEntry];
    var entry: tWriteEntry;

    if (key in writeQueues) {
      q = writeQueues[key];
    } else {
      q = default(seq[tWriteEntry]);
    }

    entry = (client = client, value = value);
    q += (sizeof(q), entry);
    writeQueues[key] = q;

    if (!(key in writeInFlight)) {
      // Issue the head-of-line write to proxy.
      writeInFlight += (key);
      IssueNextWrite(key);
    }
  }

  fun IssueNextWrite(key: int) {
    var q: seq[tWriteEntry];
    var head: tWriteEntry;

    // Precondition: key in writeQueues and writeInFlight contains key.
    if (key in writeQueues && sizeof(writeQueues[key]) > 0) {
      q = writeQueues[key];
      head = q[0];
      // Send write to proxy for the head-of-line value.
      send proxy, eStorageWrite, (caller = this, key = key, value = head.value, podId = podId);
    }
  }

  fun DeliverReadToClients(key: int, value: int, fromCache: bool) {
    var q: seq[machine];
    var i: int;
    var client: machine;
    var resp: (key: int, value: int, fromCache: bool);

    resp = (key = key, value = value, fromCache = fromCache);

    if (key in readWaiters) {
      q = readWaiters[key];
      i = 0;
      while (i < sizeof(q)) {
        client = q[i];
        send client, eReadResp, resp;
        i = i + 1;
      }
      // Clear waiters for this key.
      readWaiters -= (key);
    }

    // Allow future reads to be issued.
    if (key in readIssued) {
      readIssued -= (key);
    }
  }

  fun DeliverWriteToClient(key: int, success: bool) {
    var q: seq[tWriteEntry];
    var head: tWriteEntry;

    assert key in writeQueues && sizeof(writeQueues[key]) > 0, "Write response with no pending client";

    q = writeQueues[key];
    head = q[0];
    // Respond to the client that issued the head write.
    send head.client, eWriteResp, (key = key, success = success);

    // Pop the head.
    q -= (0);
    if (sizeof(q) == 0) {
      writeQueues -= (key);
      if (key in writeInFlight) {
        writeInFlight -= (key);
      }
    } else {
      writeQueues[key] = q;
      // Issue next write for this key.
      IssueNextWrite(key);
    }
  }
}
